import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"普罗晏比娜的吸尘器","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/普罗晏比娜的吸尘器.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/普罗晏比娜的吸尘器.md"}'),_={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/普罗晏比娜的吸尘器.md"};function d(p,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"普罗晏比娜的吸尘器",tabindex:"-1"},[s("普罗晏比娜的吸尘器 "),e("a",{class:"header-anchor",href:"#普罗晏比娜的吸尘器","aria-label":'Permalink to "普罗晏比娜的吸尘器"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序007")])])],-1),o('<h1 id="普罗晏比娜的吸尘器-1" tabindex="-1">普罗晏比娜的吸尘器 <a class="header-anchor" href="#普罗晏比娜的吸尘器-1" aria-label="Permalink to &quot;普罗晏比娜的吸尘器&quot;">​</a></h1><p>普罗晏比娜的吸尘器<br> C+1000<br> 魔幻本质</p><p>描述：整体莹白色的吸尘器，但上面沾染着暗红色的不明污渍</p><p>【法术浸润】<br> 在经历了不知名物质的侵袭后，这把吸尘器获得了神秘的力量。这视为一把法杖，以操控-器用-施法进行检定，同时自带3点法强。</p><p>【生命汲取】<br> 在你对他人发起攻击后，吸尘器亮起了微弱的光芒，你可以用一个标准动作将其依靠在一个存活的目标旁，将吸尘器打开，这视为你使用了一个攻击技，此时你获得吸血1，这表现为吸尘器缓缓发动，同时被吸取者的皮肤开始干瘪，如同生命流失一般，正常造成伤害。同时，对方需以意志豁免进行标准对抗，并会吸走对方等同于差值的能量，若如果对方没有能量或者已经耗光能量，则直接失去每2点本应消耗能量值数额的1点的意志值。</p><p>备注：普罗晏比娜是恶魔城中侍从伯爵的女仆，除了在遭遇入侵者时用跆拳道黑带的身手予以驱逐外，她们平日里最常做的工作就是打扫城堡。普罗晏比娜的吸尘器可以有效地吸收地上或墙上的血液，这和伯爵大人喜欢摔杯子的习惯有着密不可分的联系。每当伯爵看到一名贝尔蒙多家的访客时，他总是喜欢将手中装满血的高脚杯扔到地上，然后再上前和对方来一场基情对削。数百年来一直如此，意义不明。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(_,[["render",d]]);export{f as __pageData,m as default};
